query:
SELECT r.id as region_id, r.name as region_name FROM regions r;
SELECT c.id as country_id, ci.id as city_id, ci.name as city_name 
FROM countries c 
JOIN cities ci ON ci.countryId = c.id 
WHERE c.name = 'Saudi Arabia' 
AND ci.name IN ('Riyadh', 'Dammam', 'Jeddah', 'Madinah', 'Makkah', 'Qassim');

